INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'listening', 'Der Wetterbericht', 'The Weather Report', 'Hören Sie das Wetter für Deutschland.', 'Listen to the weather for Germany.', '{"type":"listen_and_choose","instructions":"Wie ist das Wetter?","exercises":[{"prompt":"Im Norden ist es heute bewölkt und es regnet leicht.","question":"Wetter im Norden?","options":["Sonnig","Regnerisch","Schnee"],"correct":1,"hint":"Listen for ''regnet''."},{"prompt":"Im Süden scheint die Sonne bei Temperaturen bis zu 25 Grad.","question":"Temperatur im Süden?","options":["15 Grad","20 Grad","25 Grad"],"correct":2,"hint":"Number check."},{"prompt":"Abends gibt es im Westen starke Gewitter.","question":"Wann gibt es Gewitter?","options":["Morgens","Mittags","Abends"],"correct":2,"hint":"Time of day."},{"prompt":"Der Wind weht schwach aus Osten.","question":"Woher kommt der Wind?","options":["Norden","Osten","Westen"],"correct":1,"hint":"Himmelsrichtung."},{"prompt":"Morgen wird es überall kühler und windig.","question":"Wetter morgen?","options":["Wärmer","Kühler"],"correct":1,"hint":"Listen for the comparative."}]}', 11),
('de', 'A2', 'listening', 'Durchsagen am Bahnhof', 'Announcements at the Station', 'Hören Sie wichtige Reiseinformationen.', 'Listen to important travel info.', '{"type":"listen_and_choose","instructions":"Welche Information ist korrekt?","exercises":[{"prompt":"Gleis vier. Der ICE nach München fährt heute zehn Minuten später ab.","question":"Wie viel Verspätung?","options":["5 Min","10 Min","15 Min"],"correct":1,"hint":"Zehn."},{"prompt":"Vorsicht bei der Einfahrt des Zuges auf Gleis acht.","question":"Welches Gleis?","options":["7","8","9"],"correct":1,"hint":"Acht."},{"prompt":"Der Regionalexpress nach Hamburg fällt heute leider aus.","question":"Was passiert mit dem Zug?","options":["Fährt pünktlich","Fällt aus","Hat Verspätung"],"correct":1,"hint":"Fällt aus (cancelled)."},{"prompt":"Bitte halten Sie den Einstieg für ankommende Fahrgäste frei.","question":"Was soll man tun?","options":["Einsteigen","Platz machen","Warten"],"correct":1,"hint":"Freihalten."},{"prompt":"Nächster Halt: Hauptbahnhof. Umstieg zum Stadtbus möglich.","question":"Wo kann man umsteigen?","options":["U-Bahn","Stadtbus","Taxi"],"correct":1,"hint":"Hören Sie das Verkehrsmittel."}]}', 12),
('de', 'A2', 'listening', 'Ein kurzes Interview', 'A Short Interview', 'Hören Sie Meinungen zu einem Thema.', 'Listen to opinions on a topic.', '{"type":"listen_and_choose","instructions":"Was sagt die Person?","exercises":[{"prompt":"Ich finde, dass Radfahren in der Stadt sehr gesund ist.","question":"Meinung über Radfahren?","options":["Gefährlich","Gesund","Teuer"],"correct":1,"hint":"Gesund (healthy)."},{"prompt":"Aber es gibt leider zu wenige Radwege im Zentrum.","question":"Was ist das Problem?","options":["Zu viele Autos","Zu wenige Radwege"],"correct":1,"hint":"Radwege (cycle paths)."},{"prompt":"Ich fahre jeden Tag mit dem Fahrrad zur Arbeit.","question":"Wie oft fährt sie?","options":["Jeden Tag","Nur am Wochenende"],"correct":0,"hint":"Jeden Tag."},{"prompt":"Das dauert nur fünfzehn Minuten.","question":"Dauer?","options":["15 Min","50 Min"],"correct":0,"hint":"Fünfzehn."},{"prompt":"Ich brauche kein Fitnessstudio mehr.","question":"Warum kein Fitnessstudio?","options":["Zu teuer","Wegen dem Radfahren"],"correct":1,"hint":"Context check."}]}', 13),
('de', 'A2', 'listening', 'Im Reisebüro', 'At the Travel Agency', 'Hören Sie ein Beratungsgespräch.', 'Listen to a consultation.', '{"type":"listen_and_choose","instructions":"Wohin geht die Reise?","exercises":[{"prompt":"Ich möchte im Sommer nach Italien fliegen.","question":"Ziel?","options":["Spanien","Italien","Griechenland"],"correct":1,"hint":"Land im Süden."},{"prompt":"Am liebsten an die Küste, in ein Hotel mit Pool.","question":"Wo?","options":["Berge","Küste"],"correct":1,"hint":"Küste (coast)."},{"prompt":"Wir sind zwei Erwachsene und ein Kind.","question":"Wie viele Personen?","options":["2","3","4"],"correct":1,"hint":"Rechnen Sie."},{"prompt":"Das Angebot inklusive Flug kostet 1200 Euro.","question":"Preis?","options":["1000","1100","1200"],"correct":2,"hint":"Tausend zweihundert."},{"prompt":"Ist das Frühstück im Preis enthalten?","question":"Was fragt der Kunde?","options":["Mittagessen","Frühstück"],"correct":1,"hint":"Mahlzeit am Morgen."}]}', 14),
('de', 'A2', 'listening', 'Über Hobbys sprechen', 'Talking about Hobbies', 'Hören Sie detaillierte Freizeitaktivitäten.', 'Listen to detailed leisure activities.', '{"type":"listen_and_choose","instructions":"Was ist das Hobby?","exercises":[{"prompt":"Ich lerne seit drei Monaten, Gitarre zu spielen.","question":"Instrument?","options":["Klavier","Gitarre"],"correct":1,"hint":"Saiteninstrument."},{"prompt":"Es ist am Anfang schwierig, aber es macht Spaß.","question":"Ist es leicht?","options":["Ja","Nein"],"correct":1,"hint":"Schwierig (difficult)."},{"prompt":"Ich übe jeden Abend eine halbe Stunde.","question":"Wie lange?","options":["15 Min","30 Min","60 Min"],"correct":1,"hint":"Halbe Stunde."},{"prompt":"Mein Ziel ist es, bald in einer Band zu spielen.","question":"Ziel?","options":["Lehrer werden","In einer Band spielen"],"correct":1,"hint":"Band."},{"prompt":"Nächste Woche habe ich mein erstes kleines Konzert.","question":"Wann ist das Konzert?","options":["Diese Woche","Nächste Woche"],"correct":1,"hint":"Zeitangabe."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'speaking', 'Vergangenheit erzählen (Perfekt)', 'Narrating Past (Perfekt)', 'Erzählen Sie, was Sie gemacht haben.', 'Tell what you have done.', '{"type":"speak_and_repeat","instructions":"Wiederholen Sie den Satz im Perfekt.","exercises":[{"prompt":"Ich habe gestern eine Pizza gegessen.","expected":"ich habe gestern eine pizza gegessen","hint":"Essen -> gegessen."},{"prompt":"Wir sind am Wochenende nach Hamburg gefahren.","expected":"wir sind am wochenende nach hamburg gefahren","hint":"Fahren -> gefahren (mit sein)."},{"prompt":"Er hat den ganzen Tag hart gearbeitet.","expected":"er hat den ganzen tag hart gearbeitet","hint":"Arbeiten -> gearbeitet."},{"prompt":"Ich bin heute Morgen im Park gejoggt.","expected":"ich bin heute morgen im park gejoggt","hint":"Joggen -> gejoggt (mit sein)."},{"prompt":"Habt ihr den Film schon gesehen?","expected":"habt ihr den film schon gesehen","hint":"Sehen -> gesehen."}]}', 11),
('de', 'A2', 'speaking', 'Gründe nennen mit "weil"', 'Giving Reasons with "weil"', 'Bilden Sie Sätze mit weil.', 'Form sentences with weil.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie den Satz mit Grund.","exercises":[{"prompt":"Ich bin müde, weil ich nicht geschlafen habe.","expected":"ich bin muede weil ich nicht geschlafen habe","hint":"Reason for tiredness."},{"prompt":"Wir bleiben zu Hause, weil es regnet.","expected":"wir bleiben zu hause weil es regnet","hint":"Reason for stay."},{"prompt":"Er lernt Deutsch, weil er in Deutschland arbeiten möchte.","expected":"er lernt deutsch weil er in deutschland arbeiten moechte","hint":"Motivation."},{"prompt":"Ich esse nichts, weil ich keinen Hunger habe.","expected":"ich esse nichts weil ich keinen hunger habe","hint":"No hunger."},{"prompt":"Sie ist glücklich, weil sie Geburtstag hat.","expected":"sie ist gluecklich weil sie geburtstag hat","hint":"Happy reason."}]}', 12),
('de', 'A2', 'speaking', 'Modalverben im Alltag', 'Modal Verbs in Daily Life', 'Wünsche und Pflichten ausdrücken.', 'Expressing wishes and duties.', '{"type":"speak_and_repeat","instructions":"Benutzen Sie das Modalverb.","exercises":[{"prompt":"Ich muss heute noch einkaufen gehen.","expected":"ich muss heute noch einkaufen gehen","hint":"Müssen (obligation)."},{"prompt":"Kannst du mir bitte beim Kochen helfen?","expected":"kannst du mir bitte beim kochen helfen","hint":"Können (ability/request)."},{"prompt":"Wir wollen am Samstag ins Kino gehen.","expected":"wir wollen am samstag ins kino gehen","hint":"Wollen (intention)."},{"prompt":"Darf ich hier mein Auto parken?","expected":"darf ich hier mein auto parken","hint":"Dürfen (permission)."},{"prompt":"Man soll jeden Tag viel Wasser trinken.","expected":"man soll jeden tag viel wasser trinken","hint":"Sollen (suggestion)."}]}', 13),
('de', 'A2', 'speaking', 'Wegbeschreibung detailliert', 'Detailed Directions', 'Den Weg genau erklären.', 'Explain the way exactly.', '{"type":"speak_and_repeat","instructions":"Erklären Sie den Weg.","exercises":[{"prompt":"Gehen Sie die Straße entlang bis zur Kreuzung.","expected":"gehen sie die strasse entlang bis zur kreuzung","hint":"Go along to intersection."},{"prompt":"Biegen Sie nach der Kirche scharf links ab.","expected":"biegen sie nach der kirche scharf links ab","hint":"Turn sharp left after church."},{"prompt":"Das Museum ist direkt hinter dem großen Parkplatz.","expected":"das museum ist direkt hinter dem grossen parkplatz","hint":"Behind parking lot."},{"prompt":"Nehmen Sie die U-Bahn Linie drei Richtung Zentrum.","expected":"nehmen sie die u bahn linie drei richtung zentrum","hint":"Subway description."},{"prompt":"Sie sehen das Gebäude auf der rechten Seite.","expected":"sie sehen das gebaeude auf der rechten seite","hint":"On the right side."}]}', 14),
('de', 'A2', 'speaking', 'Ein Zimmer beschreiben', 'Describing a Room', 'Präpositionen benutzen.', 'Using prepositions.', '{"type":"speak_and_repeat","instructions":"Wo stehen die Möbel?","exercises":[{"prompt":"Der Teppich liegt unter dem runden Tisch.","expected":"der teppich liegt unter dem runden tisch","hint":"Under the round table."},{"prompt":"Das Bild hängt über dem Sofa an der Wand.","expected":"das bild haengt ueber dem sofa an der wand","hint":"Above sofa on wall."},{"prompt":"Die Lampe steht zwischen dem Bett und dem Schrank.","expected":"die lampe steht zwischen dem bett und dem schrank","hint":"Between bed and closet."},{"prompt":"Stell die Blumen bitte in die Vase auf dem Fensterbrett.","expected":"stell die blumen bitte in die vase auf dem fensterbrett","hint":"In the vase on windowsill."},{"prompt":"Neben dem Fernseher steht ein großes Bücherregal.","expected":"neben dem fernseher steht ein grosses buecherregal","hint":"Next to TV."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'reading', 'Ein Reisebericht aus Island', 'A Travel Report from Iceland', 'Lesen Sie über die Natur Islands.', 'Read about Iceland''s nature.', '{"type":"read_and_choose","instructions":"Beantworten Sie die Fragen zum Text.","exercises":[{"sentence":"Island ist bekannt für seine Vulkane, Gletscher und heißen Quellen.","question":"Was gibt es in Island?","options":["Urwald","Gletscher","Wüste"],"correct":1,"explanation":"Gletscher werden genannt."},{"sentence":"Wir haben eine Tour mit einem Jeep durch das Hochland gemacht.","question":"Wie sind sie gereist?","options":["Mit dem Fahrrad","Mit einem Jeep"],"correct":1,"explanation":"Tour mit einem Jeep."},{"sentence":"Die Wasserfälle sind beeindruckend und sehr kraftvoll.","question":"Wie findet der Autor die Wasserfälle?","options":["Langweilig","Beeindruckend"],"correct":1,"explanation":"Beeindruckend (impressive)."},{"sentence":"Das Wetter wechselt oft mehrmals pro Stunde zwischen Sonne und Regen.","question":"Ist das Wetter stabil?","options":["Ja","Nein"],"correct":1,"explanation":"Wechselt oft."},{"sentence":"In den kleinen Fischerdörfern kann man frischen Fisch essen.","question":"Was isst man dort?","options":["Fleisch","Fisch"],"correct":1,"explanation":"Frischen Fisch."}]}', 11),
('de', 'A2', 'reading', 'Hausordnung lesen', 'Reading House Rules', 'Regeln für das Zusammenleben.', 'Rules for living together.', '{"type":"read_and_choose","instructions":"Was ist in diesem Haus erlaubt?","exercises":[{"sentence":"Die Nachtruhe beginnt um 22 Uhr und endet um 7 Uhr morgens.","question":"Darf man um 23 Uhr laut Musik hören?","options":["Ja","Nein"],"correct":1,"explanation":"Nachtruhe ab 22 Uhr."},{"sentence":"Der Müll muss nach Papier, Plastik und Restmüll getrennt werden.","question":"Muss man Müll trennen?","options":["Ja","Nein"],"correct":0,"explanation":"Müll trennen (separate trash)."},{"sentence":"Fahrräder dürfen nicht im Hausflur stehen, sondern nur im Keller.","question":"Wo parkt man das Fahrrad?","options":["Hausflur","Keller"],"correct":1,"explanation":"Nur im Keller."},{"sentence":"Haustiere sind nach Absprache mit dem Vermieter erlaubt.","question":"Darf man einen Hund haben?","options":["Generell verboten","Nach Absprache"],"correct":1,"explanation":"Nach Absprache (after consultation)."},{"sentence":"Das Treppenhaus wird wöchentlich abwechselnd von den Bewohnern gereinigt.","question":"Wer putzt das Treppenhaus?","options":["Eine Firma","Die Bewohner"],"correct":1,"explanation":"Von den Bewohnern gereinigt."}]}', 12),
('de', 'A2', 'reading', 'Gesundheitstipps im Netz', 'Online Health Tips', 'Kurze Ratschläge für den Alltag.', 'Short advice for daily life.', '{"type":"read_and_choose","instructions":"Finden Sie den richtigen Tipp.","exercises":[{"sentence":"Bildschirmpausen sind wichtig, um die Augen zu entspannen.","question":"Wofür sind Pausen wichtig?","options":["Für die Augen","Für die Ohren"],"correct":0,"explanation":"Gegen Augenmüdigkeit."},{"sentence":"Obst und Gemüse enthalten wichtige Vitamine für das Immunsystem.","question":"Was ist in Obst enthalten?","options":["Fett","Vitamine"],"correct":1,"explanation":"Vitamine."},{"sentence":"Tägliche Bewegung an der frischen Luft stärkt das Herz.","question":"Was stärkt das Herz?","options":["Bewegung draußen","Viel Schlafen"],"correct":0,"explanation":"Bewegung an frischer Luft."},{"sentence":"Vermeiden Sie Stress durch gutes Zeitmanagement und Hobbys.","question":"Wie reduziert man Stress?","options":["Mehr Arbeit","Zeitmanagement"],"correct":1,"explanation":"Gutes Zeitmanagement."},{"sentence":"Genug Schlaf (ca. 7-8 Stunden) ist für die Konzentration nötig.","question":"Wie viel Schlaf wird empfohlen?","options":["5 Stunden","7-8 Stunden"],"correct":1,"explanation":"7-8 Stunden."}]}', 13),
('de', 'A2', 'reading', 'Kultur in der Stadt', 'Culture in the City', 'Ein Veranstaltungskalender.', 'A calendar of events.', '{"type":"read_and_choose","instructions":"Wann findet was statt?","exercises":[{"sentence":"Am Freitagabend gibt es ein Jazz-Konzert im Kulturzentrum.","question":"Wann ist das Jazz-Konzert?","options":["Freitag","Samstag"],"correct":0,"explanation":"Am Freitagabend."},{"sentence":"Die Kunstausstellung im Museum ist täglich von 10 bis 18 Uhr offen.","question":"Wann öffnet das Museum?","options":["9 Uhr","10 Uhr"],"correct":1,"explanation":"Ab 10 Uhr."},{"sentence":"Am Sonntag findet auf dem Marktplatz ein Flohmarkt statt.","question":"Wo ist der Flohmarkt?","options":["Museum","Marktplatz"],"correct":1,"explanation":"Auf dem Marktplatz."},{"sentence":"Der Eintritt für das Theaterstück am Samstag kostet 15 Euro.","question":"Preis für Theater?","options":["10 Euro","15 Euro"],"correct":1,"explanation":"Kostet 15 Euro."},{"sentence":"Studenten erhalten bei allen Events einen Rabatt.","question":"Wer zahlt weniger?","options":["Nur Kinder","Studenten"],"correct":1,"explanation":"Studenten erhalten Rabatt."}]}', 14),
('de', 'A2', 'reading', 'Rezept: Apfelkuchen', 'Recipe: Apple Cake', 'Anweisungen für einen Kuchen.', 'Instructions for a cake.', '{"type":"read_and_choose","instructions":"Verstehen Sie die Backanleitung.","exercises":[{"sentence":"Zuerst vermischen Sie Mehl, Zucker und Eier in einer Schüssel.","question":"Was ist der erste Schritt?","options":["Backen","Zutaten mischen"],"correct":1,"explanation":"Zuerst vermischen."},{"sentence":"Schneiden Sie dann drei Äpfel in kleine Stücke.","question":"Wie viele Äpfel braucht man?","options":["2","3","4"],"correct":1,"explanation":"Drei Äpfel."},{"sentence":"Geben Sie den Teig in eine gefettete Form.","question":"In welche Form?","options":["Gefettet","Kalt"],"correct":0,"explanation":"Gefettete Form."},{"sentence":"Backen Sie den Kuchen bei 180 Grad für ca. 45 Minuten.","question":"Backzeit?","options":["30 Min","45 Min","60 Min"],"correct":1,"explanation":"45 Minuten."},{"sentence":"Lassen Sie den Kuchen vor dem Essen gut abkühlen.","question":"Sofort essen?","options":["Ja","Erst abkühlen lassen"],"correct":1,"explanation":"Erst abkühlen lassen."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'writing', 'Satzbau mit Modalverben', 'Sentence Structure with Modal Verbs', 'Bringen Sie die Wörter in Ordnung.', 'Put the words in order.', '{"type":"type_word","instructions":"Tippen Sie den Satz richtig (Modalverb an Position 2).","exercises":[{"prompt":"muss / ich / heute / arbeiten (I must work today)","expected":"ich muss heute arbeiten","hint":"Infinitiv am Ende."},{"prompt":"kannst / du / mir / helfen (Can you help me)","expected":"du kannst mir helfen","hint":"Subjekt + Modalverb."},{"prompt":"wir / wollen / Pizza / essen (We want to eat pizza)","expected":"wir wollen pizza essen","hint":"Essen am Satzende."},{"prompt":"darf / er / hier / rauchen (May he smoke here)","expected":"er darf hier rauchen","hint":"Rauchen am Ende."},{"prompt":"ihr / sollt / mehr / lernen (You should learn more)","expected":"ihr sollt mehr lernen","hint":"Lernen am Ende."}]}', 11),
('de', 'A2', 'writing', 'Vergangenheit: Perfekt bilden', 'Past: Forming Perfekt', 'Schreiben Sie das Partizip II.', 'Write the Participle II.', '{"type":"type_word","instructions":"Ergänzen Sie das Partizip II.","exercises":[{"prompt":"Ich habe gestern eine E-Mail [to write].","expected":"geschrieben","hint":"Schreiben -> geschrieben."},{"prompt":"Wir sind nach Berlin [to drive].","expected":"gefahren","hint":"Fahren -> gefahren."},{"prompt":"Hast du deine Hausaufgaben [to do]?","expected":"gemacht","hint":"Machen -> gemacht."},{"prompt":"Er hat ein Bier [to drink].","expected":"getrunken","hint":"Trinken -> getrunken."},{"prompt":"Sie ist nach Hause [to go].","expected":"gegangen","hint":"Gehen -> gegangen."}]}', 12),
('de', 'A2', 'writing', 'Nebensätze mit "weil"', 'Subordinate Clauses with "weil"', 'Verbinden Sie die Sätze.', 'Connect the sentences.', '{"type":"type_word","instructions":"Vollenden Sie den Satz (Verb am Ende!).","exercises":[{"prompt":"Ich lerne, weil es Spaß [to make].","expected":"macht","hint":"macht am Ende."},{"prompt":"Er schläft, weil er müde [to be].","expected":"ist","hint":"ist am Ende."},{"prompt":"Wir bleiben hier, weil es [to rain].","expected":"regnet","hint":"regnet am Ende."},{"prompt":"Sie lacht, weil sie glücklich [to be].","expected":"ist","hint":"ist am Ende."},{"prompt":"Ich esse, weil ich Hunger [to have].","expected":"habe","hint":"habe am Ende."}]}', 13),
('de', 'A2', 'writing', 'Präpositionen: Dativ oder Akkusativ', 'Prepositions: Dative or Accusative', 'Wählen Sie den Fall.', 'Choose the case.', '{"type":"type_word","instructions":"Tippen Sie den Artikel (dem/den/der).","exercises":[{"prompt":"Das Buch liegt auf [the] Tisch (maskulin, Ruhe).","expected":"dem","hint":"Dativ."},{"prompt":"Ich lege das Buch auf [the] Tisch (maskulin, Bewegung).","expected":"den","hint":"Akkusativ."},{"prompt":"Wir sitzen in [the] Garten (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Sie geht in [the] Stadt (feminin).","expected":"die","hint":"Akkusativ."},{"prompt":"Der Schlüssel steckt in [the] Tür (feminin).","expected":"der","hint":"Dativ."}]}', 14),
('de', 'A2', 'writing', 'Komparativ und Superlativ', 'Comparative and Superlative', 'Steigern Sie die Adjektive.', 'Increate the adjectives.', '{"type":"type_word","instructions":"Tippen Sie die Steigerungsform.","exercises":[{"prompt":"schnell -> schneller -> am ...","expected":"schnellsten","hint":"Superlativ."},{"prompt":"gut -> ... -> am besten","expected":"besser","hint":"Komparativ."},{"prompt":"hoch -> höher -> am ...","expected":"höchsten","hint":"Superlativ mit ch-Wechsel."},{"prompt":"groß -> ... -> am größten","expected":"groesser","hint":"Komparativ mit Umlaut."},{"prompt":"viel -> mehr -> am ...","expected":"meisten","hint":"Superlativ."}]}', 15);
